    parentName: "ul"
  }, "\uD504\uB860\uD2B8\uC5D4\uB4DC \uBD84\uB4E4\uACFC \uC7A0\uC2E4\uC5D0\uC11C \uB9CC\uB098\uC11C \uC694\uAD6C\uC0AC\uD56D \uC815\uC758\uD558\uACE0 \uBA85\uC138\uB97C \uC815\uB9AC\uD588\uB358 \uC2DC\uAC04\uC774 \uC0DD\uAC01\uBCF4\uB2E4 \uB108\uBB34 \uC990\uAC70\uC6E0\uB2E4. \uC774\uBC88 \uD398\uC5B4\uC758 \uCEE8\uC149\uC740 \u2018\uBAA8\uB4E0 \uC0DD\uAC01\uB4E4\uC744 \uAE30\uB85D\uC73C\uB85C \uB0A8\uACA8\uBCF4\uC790\u2019 \uC600\uB294\uB370, \uC758\uC678\uB85C \uC815\uB9AC\uD558\uB294 \uC2DC\uAC04\uC774 \uC990\uAC70\uC6CC\uC11C \uC55E\uC73C\uB85C\uB3C4 \uD398\uC5B4\uD558\uBA74\uC11C \uC815\uB9AC\uD558\uB294 \uC2B5\uAD00\uC744 \uAE38\uB7EC\uC57C\uACA0\uB2E4."), mdx("li", {
    parentName: "ul"
  }, "\uC990\uC120\uC0DD\uB2D8\uC740 \uB0B4\uAC00 \uC0DD\uAC01\uD558\uC9C0 \uBABB\uD55C \uBD80\uBD84\uC744 \uC798 \uC9DA\uC5B4\uC8FC\uC2E0\uB2E4. \uD5D9\uC120\uC0DD\uB2D8\uACFC \uB0B4\uAC00 \uD504\uB860\uD2B8\uC5D4\uB4DC\uC5D0\uC11C \uACE0\uB824\uD574\uC57C \uD558\uB294 \uC0AC\uD56D\uC744 \uC801\uC744 \uB54C \uC990\uC120\uC0DD\uB2D8\uC740 \uC606\uC5D0\uC11C \uC774\uB7F0 \uBB38\uC81C\uAC00 \uC788\uC744 \uC218 \uC788\uB2E4, \uC774\uB7F0 \uACBD\uC6B0\uC5D0\uB294 \uC5B4\uB5BB\uAC8C \uD574\uC57C \uD560\uAE4C\uB97C \uD56D\uC0C1 \uBB3C\uC5B4\uBD10\uC918\uC11C \uC608\uC678 \uCF00\uC774\uC2A4\uB97C \uC0DD\uAC01\uD558\uB294\uB370 \uB3C4\uC6C0\uC774 \uB9CE\uC774 \uB410\uB2E4."), mdx("li", {
    parentName: "ul"
  }, "\uD5D9\uC120\uC0DD\uB2D8\uC740 \uBB54\uAC00 \uB69D\uB531\uD574\uC624\uC2E0\uB2E4. mysql \uC5F0\uACB0 \uBB38\uC81C\uAC00 \uC788\uC5C8\uC744 \uB54C\uB3C4 \uD55C \uC2DC\uAC04 \uB9CC\uC5D0 \uD574\uACB0\uD574\uC624\uC2DC\uACE0, logback \uC124\uC815\uB3C4 \uC5B4\uB5BB\uAC8C \uC54C\uC544\uC624\uC154\uC11C \uC804\uCCB4 \uB85C\uADF8\uC640 warn \uB85C\uADF8\uB97C \uBD84\uB9AC\uD558\uB294 \uAE30\uB2A5\uAE4C\uC9C0 \uB69D\uB531 \uAD6C\uD604\uD574 \uC624\uC168\uB2E4. \uC5C4\uCCAD \uC2E0\uAE30\uD558\uB2E4 \u314B\u314B\u314B"), mdx("li", {
    parentName: "ul"
  }, "\uB098\uB3C4 \uCE6D\uCC2C\uD574\uBCF4\uC790. \uC774\uBC88 \uD398\uC5B4 \uB54C\uB294 \uAE30\uB85D\uC744 \uC5F4\uC2EC\uD788 \uD588\uB2E4. \uC5B4\uB5A4 \uACE0\uBBFC\uC744 \uD588\uACE0, \uC5B4\uB5A4 \uC120\uD0DD\uC744 \uD588\uB294\uC9C0\uB97C (\uB2E4\uB294 \uC544\uB2C8\uC9C0\uB9CC) \uC801\uC5B4\uB450\uC5B4\uC11C \uC9C0\uAE08 \uBCFC \uB54C\uB3C4 \uC774\uB7F0 \uC0DD\uAC01\uC73C\uB85C \uD310\uB2E8\uC744 \uB0B4\uB838\uB2E4\uB294 \uAC83\uC744 \uD655\uC778\uD560 \uC218 \uC788\uC5B4 \uC88B\uB2E4. \uC758\uACAC\uC744 \uB0BC \uB54C\uB294 \uC7A5\uB2E8\uC810\uC744 \uB3D9\uC2DC\uC5D0 \uC774\uC57C\uAE30 \uD588\uB2E4. \uB2E4\uB978 \uC0AC\uB78C\uC774 \uD310\uB2E8\uC744 \uD560 \uB54C \uC88B\uACE0 \uB098\uC068\uC744 \uD655\uC2E4\uD558\uAC8C \uC54C\uACE0 \uD310\uB2E8\uD558\uB294 \uAC83\uC774 \uC88B\uB2E4\uACE0 \uC0DD\uAC01\uD55C\uB2E4. \uADF8\uB798\uC11C \uC774\uAC8C \uBB34\uC870\uAC74 \uC88B\uB2E4! \uBB34\uC870\uAC74 \uB098\uC058\uB2E4! \uBCF4\uB2E4\uB294 \uC774\uB7F0 \uACBD\uC6B0\uC5D0\uB294 \uC88B\uB2E4, \uC774\uB7F0 \uACBD\uC6B0\uC5D0\uB294 \uC548 \uC88B\uC744 \uC218 \uC788\uB2E4\uB77C\uB294 \uD654\uBC95\uC73C\uB85C \uC758\uACAC\uC744 \uC81C\uC548\uD558\uB2C8 \uB2E4\uB978 \uC0AC\uB78C\uC774 \uC120\uD0DD\uD558\uAE30\uC5D0 \uC218\uC6D4\uD588\uB358 \uAC83 \uAC19\uB2E4."))), mdx("li", {
    parentName: "ul"
  }, "matzip\uC5D0 \uC880 \uB354 \uC2DC\uAC04\uC744 \uD22C\uC790\uD588\uB2E4. \uC624\uB9AC\uC640 \uD398\uC5B4\uB3C4 \uC5F4\uC2EC\uD788 \uD558\uACE0, PR \uC62C\uB77C\uC628 \uAC83\uB3C4 \uBCF4\uB294 \uC2DC\uAC04\uC744 \uAC00\uC84C\uB2E4. \uC2DC\uAC04\uC774 \uB9CE\uC9C0 \uC54A\uC544 \uC18C\uD640\uD588\uB358 \uC810\uC774 \uC544\uC27D\uB2E4. \uC55E\uC73C\uB85C\uC758 \uACC4\uD68D\uC5D0 \uB300\uD574 \uD68C\uC758\uD558\uB294 \uC2DC\uAC04\uB3C4 \uAC00\uC84C\uB294\uB370, \uC758\uACAC\uC774 \uBE60\uB974\uAC8C \uD558\uB098\uB85C \uBAA8\uC774\uC9C0\uB294 \uC54A\uC558\uC9C0\uB9CC \uB098\uB294 \uADF8\uAC83\uB300\uB85C \uC88B\uC558\uB2E4\uACE0 \uC0DD\uAC01\uD55C\uB2E4. \uACC4\uD68D\uB300\uB85C \uC548 \uB418\uB294 \uAC83\uB3C4, \uD558\uACE0 \uC2F6\uC740 \uAC8C \uB9CE\uC740 \uAC83\uB3C4, \uC11C\uB85C\uC758 \uAC00\uCE58\uAD00\uACFC \uC0DD\uAC01\uC774 \uB2E4\uB978 \uAC83\uB3C4 \uC5B4\uCA4C\uBA74 \uB2F9\uC5F0\uD55C \uAC83\uC774\uB77C \uC790\uC5F0\uC2A4\uB7EC\uC6B4 \uC77C\uC774\uC5C8\uB2E4. \uB9CC\uC57D \uC11C\uB85C\uC758 \uC758\uACAC\uC744 \uC911\uC7AC\uD558\uB294 \uC0AC\uB78C\uC774 \uD544\uC694\uD574\uC9C4\uB2E4\uBA74 \uB0B4\uAC00 \uD574\uBCF4\uACE0 \uC2F6\uB2E4. \uB098\uB294 \uD06C\uAC8C \uC758\uACAC\uC774 \uC788\uB294 \uC0AC\uB78C\uC774 \uC544\uB2C8\uB77C\uC11C, \uC758\uACAC\uC744 \uC880 \uB354 \uAC1D\uAD00\uC801\uC73C\uB85C \uBCFC \uC218 \uC788\uC9C0 \uC54A\uC744\uAE4C \uC2F6\uB2E4. \uADF8\uB0E5 \uADF8\uB807\uB2E4\uACE0 \u314B\u314B"), mdx("li", {
    parentName: "ul"
  }, "\uADF8\uAC83\uACFC\uB294 \uBCC4\uAC1C\uB85C matzip\uC5D0\uC11C \uBC30\uC6B0\uB294 \uB0B4\uC6A9\uC774 \uB9CE\uB2E4. \uC11C\uBE0C\uBAA8\uB4C8\uB3C4 matzip\uC774 \uC544\uB2C8\uC5C8\uB2E4\uBA74 \uBAB0\uB790\uC744 \uAC70\uACE0, \uBA40\uD2F0 \uBAA8\uB4C8\uC774\uBA70 graceful shutdown\uB3C4 \uD558\uB098\uB3C4 \uBAB0\uB790\uC744 \uAC83 \uAC19\uC740\uB370 \uC54C\uC544\uAC00\uB294 \uD0A4\uC6CC\uB4DC\uB4E4\uC774 \uB9CE\uC544\uC11C \uC88B\uB2E4. 4\uAE30 \uC624\uB9AC\uAC00 \uC5F4\uC2EC\uD788 \uD398\uC5B4\uD574\uC8FC\uC2DC\uB294 \uAC83\uB3C4 \uAC10\uC0AC\uD558\uB2E4. \uD1F4\uADFC\uD558\uACE0 \uC194\uC9C1\uD788 \uC26C\uACE0 \uC2F6\uC73C\uC2E4 \uD150\uB370 \uC6B0\uB9AC\uAC00 matzip\uC744 \uC774\uC5B4\uB098\uAC08 \uC6B0\uD14C\uCF54 \uD6C4\uBC30 \uAE30\uC218\uB77C\uB294 \uC774\uC720\uB9CC\uC73C\uB85C \uB3C4\uC6C0\uC744 \uC8FC\uC2DC\uB294 \uAC83\uC5D0 \uAD49\uC7A5\uD55C \uAC10\uC0AC\uB97C \uB290\uB07C\uACE0 \uC788\uB2E4. \uAC10\uC0AC\uD569\uB2C8\uB2E4 \uC624\uB9AC \uD83E\uDEF6\uD83C\uDFFB"), mdx("li", {
    parentName: "ul"
  }, "\uC0C8\uC2F9 \uAD50\uC2E4\uC774 \uB05D\uB0AC\uB2E4. \uC778\uD130\uD398\uC774\uC2A4\uAE4C\uC9C0 \uB2E4\uB8E8\uC9C0 \uBABB\uD574 \uC544\uC26C\uC6C0\uC744 \uB290\uB07C\uC9C0\uB9CC, \uADF8\uB798\uB3C4 \uAC1C\uC778\uC801\uC73C\uB85C \uC9C0\uAE08\uAE4C\uC9C0 \uAC15\uC758\uD588\uB358 \uAC83\uC5D0 \uBE44\uD574 \uB9CE\uC774 \uB298\uC5C8\uB2E4\uACE0 \uB290\uB080\uB2E4. \uCC98\uC74C\uC5D0\uB294 \uB2E8\uC9C0 \uC815\uBCF4 \uC804\uB2EC\uC744 \uD558\uAE30 \uC704\uD574 \uAE09\uAE09\uD574\uC11C \uC7AC\uC791\uB144\uAE4C\uC9C0\uB294 \uC194\uC9C1\uD788 \uC0C8\uC2F9\uB4E4\uC5D0\uAC8C \uD06C\uAC8C \uB3C4\uC6C0\uC774 \uB41C \uAC74 \uC544\uB2C8\uC5C8\uB2E4\uACE0 \uC0DD\uAC01\uD55C\uB2E4. \uADF8\uB807\uC9C0\uB9CC \uC774\uBC88\uC5D0\uB294 \uC65C \uC774\uAC78 \uC368\uC57C \uD558\uB294\uC9C0, \uC65C \uC774\uB807\uAC8C \uD558\uB294 \uAC83\uC774 \uC88B\uC740\uC9C0 \uB0B4\uAC00 \uACE0\uBBFC\uD588\uB358 \uBD80\uBD84\uC744 \uCD5C\uB300\uD55C \uC804\uB2EC\uD558\uB824\uACE0 \uC560\uC37C\uB2E4. \uB2E8\uC21C\uD788 int\uC758 \uBC94\uC704\uB098 \uC0C1\uC18D\uC744 \uD558\uB294 \uBC29\uBC95\uC744 \uC54C\uB824\uC8FC\uB294 \uAC8C \uC544\uB2C8\uB77C, \uC65C \uBCC0\uC218\uB97C \uC368\uC57C\uD558\uACE0 \uC65C final\uC744 \uC368\uC57C \uD558\uB294\uC9C0 \uB4F1 \uAC1C\uC778\uC801\uC73C\uB85C \uACE0\uBBFC\uD588\uB358 \uB0B4\uC6A9\uB4E4\uC744 \uC804\uB2EC\uD558\uB294 \uAC83\uC5D0 \uC911\uC2EC\uC744 \uB450\uC5B4\uC11C \uB098\uB3C4 \uC218\uC5C5\uD558\uBA74\uC11C \uC990\uAC70\uC6E0\uB2E4. \uD55C \uC8FC\uB9CC \uB354 \uC788\uC5C8\uB2E4\uBA74 \uC88B\uC558\uACA0\uB2E4\uB294 \uC0DD\uAC01\uB3C4 \uD588\uB2E4. (\uADF8\uB807\uC9C0\uB9CC \uC55E\uC73C\uB85C 2\uC8FC\uAC00 \uC2DC\uD5D8\uAE30\uAC04\uC774\uAE30 \uB54C\uBB38\uC5D0 \uC695\uC2EC\uC740 \uB9C8\uC74C\uC5D0 \uACE0\uC774 \uC811\uC5B4\uB450\uC5C8\uB2E4\u2026)")), mdx("h2", {
